#pragma once

// irq_vector_traits.hpp — Task 1.1 (add-irq-vector-hal)
//
// IrqVectorTraits<PeripheralId> — generated by alloy-cpp-emit from IR
// interrupt data.  Maps a PeripheralId to its CMSIS IRQ number.
//
// Default (primary) specialization: not present → IrqId invalid.
// Devices with IRQ data in their IR will have specializations emitted by the
// codegen template (templates/irq_vector_traits.hpp.j2).

#include <cstdint>

#include "hal/irq/irq_id.hpp"
#include "device/runtime.hpp"

namespace alloy::hal::irq {

/// Primary template — peripheral has no known IRQ.
template <device::runtime::PeripheralId P>
struct IrqVectorTraits {
    static constexpr bool kPresent = false;
    static constexpr IrqId kIrqId  = kInvalidIrqId;
};

/// Helper: does a peripheral have a valid IRQ?
template <device::runtime::PeripheralId P>
inline constexpr bool kHasIrq =
    IrqVectorTraits<P>::kPresent && IrqVectorTraits<P>::kIrqId.is_valid();

}  // namespace alloy::hal::irq
